@dataclass
class DataGovernanceRecord:
    dataset_id: str
    source_description: str
    collection_method: str
    known_biases: list[str]
    bias_mitigations: list[str]
    demographic_breakdown: Optional[dict]   # e.g. {"gender": {"M": 0.52, "F": 0.48}}
    data_start_date: str
    data_end_date: str
    size: int

    def completeness_check(self) -> list[str]:
        """Return list of missing required fields for Article 10 compliance."""
        issues = []
        if not self.known_biases:
            issues.append("known_biases must be documented (even if empty list with rationale)")
        if not self.demographic_breakdown:
            issues.append("demographic_breakdown required for employment/credit use cases")
        return issues

@dataclass
class SystemCard:
    """EU AI Act Article 13 — transparency documentation for deployers."""

    system_name: str
    version: str
    intended_purpose: str
    prohibited_uses: list[str]
    accuracy_metrics: dict          # e.g. {"precision": 0.91, "recall": 0.88}
    known_limitations: list[str]
    human_oversight_required: bool
    oversight_instructions: str     # what a human operator must verify
    monitoring_instructions: str    # how to detect drift in production
    contact_for_incidents: str

    def validate(self) -> list[str]:
        issues = []
        if self.human_oversight_required and not self.oversight_instructions:
            issues.append("oversight_instructions must describe what the human checks")
        if not self.prohibited_uses:
            issues.append("prohibited_uses list is required even if empty")
        return issues

from pathlib import Path
import json

class ConformityAssessmentBundle:
    """
    Package the artefacts required for EU AI Act conformity assessment.
    Upload to the EU database before market placement.
    """

    def __init__(self, output_dir: Path):
        self.output_dir = output_dir
        output_dir.mkdir(parents=True, exist_ok=True)
        self._items: dict[str, str] = {}

    def add_risk_register(self, register: "RiskRegister") -> None:
        path = self.output_dir / "risk_register.json"
        path.write_text(json.dumps(register.to_audit_report(), indent=2))
        self._items["risk_register"] = str(path)

    def add_system_card(self, card: "SystemCard") -> None:
        path = self.output_dir / "system_card.json"
        path.write_text(json.dumps(card.__dict__, indent=2))
        self._items["system_card"] = str(path)

    def add_test_report(self, report_path: Path) -> None:
        self._items["test_report"] = str(report_path)

    def add_data_governance(self, records: list["DataGovernanceRecord"]) -> None:
        path = self.output_dir / "data_governance.json"
        path.write_text(json.dumps([r.__dict__ for r in records], indent=2))
        self._items["data_governance"] = str(path)

    def missing_items(self) -> list[str]:
        required = {"risk_register", "system_card", "test_report", "data_governance"}
        return sorted(required - self._items.keys())

    def is_complete(self) -> bool:
        return len(self.missing_items()) == 0

    def generate_declaration(self) -> dict:
        if not self.is_complete():
            raise RuntimeError(f"Missing: {self.missing_items()}")
        return {
            "declaration_type": "EU Declaration of Conformity",
            "regulation": "EU 2024/1689 (AI Act)",
            "artefacts": self._items,
        }
